UPDATE public.questions SET
  stimulus_text = 'Psychologists testing memory task 22 reported that participants who slept eight hours recalled word lists more accurately than those who stayed awake, even when both groups studied equally long. The awake group was kept in a quiet lounge with books and puzzles to prevent napping, yet their recall still lagged behind the sleep group on both immediate and delayed tests. Brain-imaging subsamples showed differences in hippocampal activity during retrieval, aligning with theories that sleep consolidates declarative memories. The researchers caution that the study measured short lists under lab conditions and may not generalize to complex real-world learning. Still, the controlled comparison isolates sleep as the key variable because study time, list difficulty, and initial exposure were matched. The passage presents sleep as a cognitive process with measurable downstream effects on recall. The authors plan a replication with longer study materials to test whether the consolidation effect scales with content complexity.',
  question_text = 'Which choice best states the main idea of the passage?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"Protecting herbivorous fish helps reefs recover because grazing controls algae and enables coral settlement.","is_correct":true,"explanation":"The passage centers on grazing, algae control, and coral recruitment as interconnected processes."},{"id":"B","text":"Reefs never recover once algae appear, regardless of grazing or recruitment.","is_correct":false,"explanation":"The passage describes recovery mechanisms; it does not claim permanent loss once algae appear."},{"id":"C","text":"The passage rejects scientific study of reefs in favor of anecdotal fishing reports.","is_correct":false,"explanation":"The passage cites research and field surveys; it does not reject scientific methods."},{"id":"D","text":"Coral larvae cannot survive on any hard surface mentioned in marine research.","is_correct":false,"explanation":"The passage states larvae settle on bare rock when grazing permits it."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The passage develops a causal chain linking herbivory to reef recovery. The stimulus anchors the correct choice in language such as "Psychologists testing memory task 22 reported that participants who slept eight hours recalled word …". Choice A is correct: x. Incorrect options contradict explicit details, import absent information, or answer a different question than the stem asks.',
