UPDATE public.questions SET
  stimulus_text = 'Historians examining trade route 2 note that camel caravans carried not only goods but also astronomical tables, spreading navigation techniques across deserts long before printed maps existed. Merchants who survived the crossing depended on star charts copied onto leather scrolls, and those copies often accumulated marginal notes from later travelers. A ledger recovered near route 2 lists dates, caravan leaders, and the scientific texts exchanged at each oasis, suggesting that commerce and scholarship moved together. When one city tightened tariffs, caravans rerouted through secondary wells, and the astronomical knowledge rerouted with them. Modern scholars therefore treat desert trade networks as early information highways rather than simple supply chains. The passage emphasizes how practical navigation needs drove the circulation of technical knowledge among communities that rarely shared a written language. Recent digitization projects have linked surviving ledger fragments to star-chart marginalia, strengthening the case for integrated commercial and intellectual exchange.',
  question_text = 'Which finding from the passage, if true, would best support the author''s claim about organizational adaptation during supply-chain disruption?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"National chains never order from wholesalers under any circumstances.","is_correct":false,"explanation":"Irrelevant to adaptation speed during logistics failures."},{"id":"B","text":"Local wholesalers could restock small retailers within days while centralized distribution remained delayed.","is_correct":true,"explanation":"Explains why small retailers adapted quickly via local restocking."},{"id":"C","text":"Supply chains never stall in modern economies.","is_correct":false,"explanation":"Contradicts the passage''s premise that supply chains stalled."},{"id":"D","text":"Printed astronomical tables spread faster than camel caravans.","is_correct":false,"explanation":"Belongs to a different passage about desert trade."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The passage claims small retailers adapted faster when logistics failed. The stimulus anchors the correct choice in language such as "Historians examining trade route 2 note that camel caravans carried not only goods but also astronom…". Choice B is correct: . Incorrect options contradict explicit details, import absent information, or answer a different question than the stem asks.',
